let renderRoot = (e) => {
  console.log(e);
};

let state = {
  messegData: [],
  newChanges: "",
};

export const addPost = () => {
  if (state.newChanges === "") {
    return;
  }
  let newPost = {
    id: 5,
    messege: state.newChanges,
    like: 23,
  };
  console.log(newPost);
  state.messegData.push(newPost);

  renderRoot(state);
};
console.log(state);
export const upDateChange = (newChange) => {
  state.newChanges = newChange;
};

export let subscribe = (observer) => {
  renderRoot(observer);
};

export default state;
